{
  "family": "Pinner Reaction",
  "candidate": {
    "substrate_smiles": [
      "CC#N",
      "CCO"
    ],
    "product_smiles": [
      "CC(=[NH2+])OCC.[Cl-]"
    ],
    "optional_reagent_smiles": [
      "Cl"
    ],
    "rationale": "This reaction shows the formation of an imino ether hydrochloride salt (a Pinner salt) from a simple aliphatic nitrile (acetonitrile) and a simple alcohol (ethanol) in the presence of hydrogen chloride. This is the quintessential first step of the Pinner reaction, as described in most organic chemistry textbooks. The reactants are small, acyclic, and lack complex functional groups, making it a clear and unambiguous example of the core transformation.",
    "collision_avoidance_note": "The use of simple, saturated aliphatic reactants (acetonitrile, ethanol) avoids collision with reactions involving aromatic systems, complex functional groups, or specific ring structures. The product is the characteristic imino ether salt, which is specific to the Pinner reaction and distinct from products of other nitrile transformations like hydrolysis to amides or reduction to amines."
  }
}
